{"content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class EnumTrailingCommaSemicolonTest {
    private val ruleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                { NoSemicolonsRule() },
                { WrappingRule() },
                { IndentationRule() }
            )
        )

    @Test
    fun `enum with members and semicolon and missing trailing comma`() {
        val code = """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
        """.trimIndent()

        // This should pass without violations on the first run when formatting
        ruleAssertThat(code)
            .withEditorConfigOverride(TrailingCommaOnDeclarationSiteRule.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .isFormattedAs("""
                enum class TestEnum() {
                    A,
                    B,
                    ;

                    companion object {
                        const val A_NUMBER = 1L
                    }
                }
            """.trimIndent())
    }
}
