329→public val ASTNode.column: Int
330→    get() {
331→        var leaf = this.prevLeaf()
332→        var offsetToTheLeft = 0
333→        while (leaf != null) {
334→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
335→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
336→                break
337→            }
338→            offsetToTheLeft += leaf.textLength
339→            leaf = leaf.prevLeaf()
340→        }
341→        return offsetToTheLeft + 1
342→    }
