373→/**
374→ * Verifies that a whitespace leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in
375→ * case any of the boundary nodes [from] or [to] is a whitespace leaf containing a newline.
376→ */
377→@Deprecated(
378→    message = "Marked for removal in KtLint 0.49",
379→    replaceWith = ReplaceWith("hasNewLineInClosedRange(from, to)"),
380→)
381→public fun hasWhiteSpaceWithNewLineInClosedRange(from: ASTNode, to: ASTNode): Boolean =
382→    from.isWhiteSpaceWithNewline() ||
383→        leavesInOpenRange(from, to).any { it.isWhiteSpaceWithNewline() } ||
384→        to.isWhiteSpaceWithNewline()
385→
386→/**
387→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
388→ * the boundary nodes [from] or [to] contains a newline.
389→ */
390→public fun hasNewLineInClosedRange(from: ASTNode, to: ASTNode): Boolean =
391→    from.isWhiteSpaceWithNewline() ||
392→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
393→        to.isWhiteSpaceWithNewline()
394→
395→/**
396→ * Verifies that no whitespace leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes
397→ * [from] and [to] should not be a whitespace leaf containing a newline.
398→ */
399→@Deprecated(
400→    message = "Marked for removal in KtLint 0.49",
401→    replaceWith = ReplaceWith("noNewLineInClosedRange(from, to)"),
402→)
403→public fun noWhiteSpaceWithNewLineInClosedRange(from: ASTNode, to: ASTNode): Boolean =
404→    !from.isWhiteSpaceWithNewline() &&
405→        leavesInOpenRange(from, to).none { it.isWhiteSpaceWithNewline() } &&
406→        !to.isWhiteSpaceWithNewline()
407→
408→/**
409→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
410→ * should not contain a newline.
411→ */
412→public fun noNewLineInClosedRange(from: ASTNode, to: ASTNode): Boolean =
413→    !from.isWhiteSpaceWithNewline() &&
414→        leavesInOpenRange(from, to).none { it.textContains('\n') } &&
415→        !to.isWhiteSpaceWithNewline()
416→
417→/**
418→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
419→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
420→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
421→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
422→ */
423→public fun leavesInOpenRange(from: ASTNode, to: ASTNode): Sequence<ASTNode> =
424→    from
425→        .leaves()
426→        .takeWhile { it != to && it != to.firstChildNode }
