 26→public class NoSemicolonsRule : Rule("no-semi") {
 27→    override fun beforeVisitChildNodes(
 28→        node: ASTNode,
 29→        autoCorrect: Boolean,
 30→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 31→    ) {
 32→        if (node.elementType != SEMICOLON) {
 33→            return
 34→        }
 35→        val nextLeaf = node.nextLeaf()
 36→        val prevCodeLeaf = node.prevCodeLeaf()
 37→        if (nextLeaf.doesNotRequirePreSemi() && isNoSemicolonRequiredAfter(node)) {
 38→            emit(node.startOffset, "Unnecessary semicolon", true)
 39→            if (autoCorrect) {
 40→                val prevLeaf = node.prevLeaf(true)
 41→                node.treeParent.removeChild(node)
 42→                if (prevLeaf.isWhiteSpace() && (nextLeaf == null || nextLeaf.isWhiteSpace())) {
 43→                    node.treeParent.removeChild(prevLeaf!!)
 44→                }
 45→            }
 46→        } else if (nextLeaf !is PsiWhiteSpace) {
 47→            val prevLeaf = node.prevLeaf()
 48→            if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) { // \n;{
 49→                return
 50→            }
 51→            // todo: move to a separate rule
 52→            emit(node.startOffset + 1, "Missing spacing after \";\"", true)
 53→            if (autoCorrect) {
 54→                node.upsertWhitespaceAfterMe(" ")
 55→            }
 56→        }
 57→    }
 58→
 59→    private fun ASTNode?.doesNotRequirePreSemi(): Boolean {
 60→        if (this == null) {
 61→            return true
 62→        }
 63→        if (this is PsiWhiteSpace) {
 64→            val nextLeaf = nextLeaf {
 65→                val psi = it.psi
 66→                it !is PsiWhiteSpace && it !is PsiComment && psi.getStrictParentOfType<KDoc>() == null &&
 67→                    psi.getStrictParentOfType<KtAnnotationEntry>() == null
 68→            }
 69→            return (
 70→                nextLeaf == null || // \s+ and then eof
 71→                    textContains('\n') && nextLeaf.elementType != KtTokens.LBRACE
 72→                )
 73→        }
 74→        return false
 75→    }
 76→
 77→    private fun isNoSemicolonRequiredAfter(node: ASTNode): Boolean {
 78→        val prevCodeLeaf =
 79→            node.prevCodeLeaf()
 80→                ?: return true
 81→        if (prevCodeLeaf.elementType == OBJECT_KEYWORD) {
 82→            // https://github.com/pinterest/ktlint/issues/281
 83→            return false
 84→        }
 85→
 86→        val parent = prevCodeLeaf.treeParent?.psi
 87→        if (parent is KtLoopExpression && parent !is KtDoWhileExpression && parent.body == null) {
 88→            // https://github.com/pinterest/ktlint/issues/955
 89→            return false
 90→        }
 91→        if (parent is KtIfExpression && parent.then == null) {
 92→            return false
 93→        }
 94→        // In case of an enum entry the semicolon (e.g. the node) is a direct child node of enum entry
 95→        if (node.treeParent.elementType == ENUM_ENTRY) {
 96→            return node.isLastCodeLeafBeforeClosingOfClassBody()
 97→        }
 98→
 99→        return true
100→    }
101→
102→    private fun ASTNode?.isLastCodeLeafBeforeClosingOfClassBody() =
103→        getLastCodeLeafBeforeClosingOfClassBody() == this
104→
105→    private fun ASTNode?.getLastCodeLeafBeforeClosingOfClassBody() =
106→        this
107→            ?.parent(CLASS_BODY)
108→            ?.lastChildLeafOrSelf()
109→            ?.prevCodeLeaf()
110→}
