{"content":"import org.jetbrains.kotlin.cli.jvm.compiler.EnvironmentConfigFiles
import org.jetbrains.kotlin.cli.jvm.compiler.KotlinCoreEnvironment
import org.jetbrains.kotlin.com.intellij.openapi.util.Disposer
import org.jetbrains.kotlin.com.intellij.psi.PsiElement
import org.jetbrains.kotlin.com.intellij.psi.PsiRecursiveElementVisitor
import org.jetbrains.kotlin.config.CompilerConfiguration
import org.jetbrains.kotlin.psi.KtFile
import org.jetbrains.kotlin.psi.KtPsiFactory

fun main() {
    val project = KotlinCoreEnvironment.createForProduction(
        Disposer.newDisposable(),
        CompilerConfiguration(),
        EnvironmentConfigFiles.JVM_CONFIG_FILES
    ).project
    val psiFactory = KtPsiFactory(project)
    val code = """
        enum class TestEnum {
            A,
            B;
            fun foo() {}
        }
    """.trimIndent()
    val file = psiFactory.createFile("test.kt", code)
    dump(file)
}

fun dump(element: PsiElement, indent: String = "") {
    println("${indent}${element.javaClass.simpleName} (${element.node.elementType}): ${element.text.replace("\n", "\\n")}")
    element.children.forEach { dump(it, "$indent  ") }
}
